class RestError extends Error {
  constructor(message, code = 'RestError', statusCode = 500) {
    super(message);
    this.code = code;
    this.statusCode = statusCode;
  }
}

class TableClient {
  static fromConnectionString() {
    return new TableClient();
  }

  async createTable() {
    return { succeeded: true };
  }

  async getEntity() {
    const error = new RestError('Entity not found', 'ResourceNotFound', 404);
    throw error;
  }

  async upsertEntity() {
    return { succeeded: true };
  }

  async deleteEntity() {
    return { succeeded: true };
  }
}

module.exports = { TableClient, RestError };
module.exports.default = module.exports;
